import React, { useState, useEffect } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';
import { View, Text, TextInput, TouchableOpacity, Alert } from 'react-native';

const Stack = createStackNavigator();

const AuthContext = React.createContext();

const AuthProvider = ({ children }) => {
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadToken();
  }, []);

  const loadToken = async () => {
    try {
      const token = await AsyncStorage.getItem('userToken');
      const userData = await AsyncStorage.getItem('userData');
      
      if (token) {
        setUserToken(token);
        setUserData(JSON.parse(userData));
      }
    } catch (error) {
      console.error('Error loading token:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const signIn = async (token, userData) => {
    try {
      await AsyncStorage.setItem('userToken', token);
      await AsyncStorage.setItem('userData', JSON.stringify(userData));
      setUserToken(token);
      setUserData(userData);
    } catch (error) {
      console.error('Error saving token:', error);
    }
  };

  const signOut = async () => {
    try {
      await AsyncStorage.removeItem('userToken');
      await AsyncStorage.removeItem('userData');
      setUserToken(null);
      setUserData(null);
    } catch (error) {
      console.error('Error removing token:', error);
    }
  };

  return (
    <AuthContext.Provider value={{ signIn, signOut, userToken, userData, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

const AuthScreen = ({ navigation }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { signIn } = React.useContext(AuthContext);

  const handleSignIn = async () => {
    try {
      // Mock authentication - replace with your API call
      if (email && password) {
        const mockToken = 'mock-jwt-token-' + Math.random().toString(36).substr(2, 9);
        const mockUserData = { id: 1, email, name: 'User' };
        signIn(mockToken, mockUserData);
      } else {
        Alert.alert('Error', 'Please enter email and password');
      }
    } catch (error) {
      Alert.alert('Error', 'Authentication failed');
    }
  };

  return (
    <View style={{ flex: 1, padding: 20, justifyContent: 'center' }}>
      <Text style={{ fontSize: 24, marginBottom: 20 }}>Sign In</Text>
      <TextInput
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        style={{ borderWidth: 1, padding: 10, marginBottom: 10 }}
      />
      <TextInput
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
        style={{ borderWidth: 1, padding: 10, marginBottom: 20 }}
      />
      <TouchableOpacity onPress={handleSignIn} style={{ backgroundColor: 'blue', padding: 15, borderRadius: 5 }}>
        <Text style={{ color: 'white', textAlign: 'center' }}>Sign In</Text>
      </TouchableOpacity>
    </View>
  );
};

const HomeScreen = ({ navigation }) => {
  const { signOut, userData } = React.useContext(AuthContext);

  return (
    <View style={{ flex: 1, padding: 20, justifyContent: 'center' }}>
      <Text style={{ fontSize: 24, marginBottom: 20 }}>Welcome {userData?.name}</Text>
      <TouchableOpacity onPress={() => signOut()} style={{ backgroundColor: 'red', padding: 15, borderRadius: 5 }}>
        <Text style={{ color: 'white', textAlign: 'center' }}>Sign Out</Text>
      </TouchableOpacity>
    </View>
  );
};

const App = () => {
  const { userToken, isLoading } = React.useContext(AuthContext);

  if (isLoading) {
    return <View style={{ flex: 1, justifyContent: 'center' }}><Text>Loading...</Text></View>;
  }

  return (
    <NavigationContainer>
      <Stack.Navigator>
        {userToken ? (
          <Stack.Screen name="Home" component={HomeScreen} options={{ headerShown: false }} />
        ) : (
          <Stack.Screen name="Auth" component={AuthScreen} options={{ headerShown: false }} />
        )}
      </Stack.Navigator>
    </NavigationContainer>
  );
};

export { AuthProvider, AuthContext, App };